        current_background_theta_values=lambda **kwargs: [4.0, 5.0],
        current_geometry_theta_offset=lambda **kwargs: 0.0,
        geometry_manual_pairs_for_index=lambda idx: list(pairs_by_background.get(int(idx), [])),
