def _new4_ladder_provider_identity_pair(
    index: int,
    *,
    full_source: bool = True,
    missing_identity: bool = False,
):
    hkl = (int(index), 0, 1)
    identity = {}
    if not missing_identity:
        identity.update(
            {
                "normalized_hkl": list(hkl),
                "source_table_index": int(index),
                "source_row_index": 0,
                "source_peak_index": int(index % 2),
                "source_branch_index": int(index % 2),
                "source_label": "primary",
                "label": f"{hkl[0]},{hkl[1]},{hkl[2]}",
            }
        )
        if full_source:
            identity.update(
                {
                    "source_reflection_index": int(index),
                    "source_reflection_namespace": "full_reflection",
                    "source_reflection_is_full": True,
                }
            )
    provider_pair = {
        "pair_index": int(index),
        "provider_pair_index": int(index),
        "dataset_pair_index": int(index),
        "selected_source_identity_canonical": identity,
        "background_point": [10.0 + index, 20.0 + index],
        "rebinding_fallback_used": False,
        "fallback_reason": None,
    }
    manual_pair = {
        "pair_index": int(index),
        "provider_pair_index": int(index),
        "dataset_pair_index": int(index),
        "selected_source_identity_canonical": identity,
        "solver_measured_point": [10.0 + index, 20.0 + index],
    }
    measured_row = {
        "hkl": hkl,
        "label": f"{hkl[0]},{hkl[1]},{hkl[2]}",
        "x": 10.0 + index,
        "y": 20.0 + index,
        "fit_source_resolution_kind": "q_group_fallback",
    }
    return provider_pair, manual_pair, measured_row


def _new4_dynamic_trial_source_rows(*, full_source: bool = True) -> list[dict[str, object]]:
    rows = []
    for index in range(7):
        hkl = (int(index), 0, 1)
        branch_slot = "00l_collapsed" if hkl[0] == 0 and hkl[1] == 0 else int(index % 2)
        row = {
            "hkl": hkl,
            "normalized_hkl": hkl,
            "source_label": "primary",
            "source_kind": "sim_visual_caked_deg",
            "actual_source": "sim_visual_caked_deg",
            "coordinate_provenance": "trial_geometry_projection",
            "projection_frame": "caked_display",
            "is_dynamic_trial_row": True,
            "source_table_index": int(index),
            "source_row_index": 0,
            "source_branch_index": int(index % 2),
            "source_peak_index": int(index % 2),
            "physical_branch_slot": branch_slot,
            "fit_qr_branch_key": {
                "q_group_key": None,
                "hkl": list(hkl),
                "physical_branch_slot": branch_slot,
                "source_branch_index": int(index % 2),
                "source_peak_index": int(index % 2),
            },
        }
        if full_source:
            row.update(
                {
                    "source_reflection_index": int(index),
                    "source_reflection_namespace": "full_reflection",
                    "source_reflection_is_full": True,
                }
            )
        rows.append(row)
    return rows


def _new4_dynamic_trial_source_rows_payload(
    *,
    full_source: bool = True,
) -> dict[str, object]:
    rows = _new4_dynamic_trial_source_rows(full_source=full_source)
    return {
        "available": True,
        "source": "synthetic_dynamic_trial_source_rows",
        "row_count": len(rows),
        "rows": [dict(row) for row in rows],
        "source_diagnostics": {
            "geometry_fit_trial_source_rows_stages": {
                "source_rows_after_provider_coverage_promotion": {
                    "required_pair_count": 7,
                    "dynamic_source_row_count": len(rows),
                    "missing_dynamic_pair_count": 0,
                    "stale_coordinate_pair_count": 0,
                }
            }
        },
    }


def _new4_ladder_context_with_provider_rows(
    *,
    full_source: bool,
    missing_identity: bool = False,
):
    base_prepared_run, _postprocess_config = _make_prepared_run(joint_background_mode=False)
    provider_pairs = []
    manual_pairs = []
    measured_rows = []
    miller = []
    for index in range(7):
        provider_pair, manual_pair, measured_row = _new4_ladder_provider_identity_pair(
            index,
            full_source=full_source,
            missing_identity=missing_identity,
        )
        provider_pairs.append(provider_pair)
        manual_pairs.append(manual_pair)
        measured_rows.append(measured_row)
        miller.append([index, 0, 1])
    trial_source_payload = _new4_dynamic_trial_source_rows_payload(full_source=full_source)
    prepared_run = replace(
        base_prepared_run,
        fit_params={
            "center_x": 32.0,
            "center_y": 33.0,
            "theta_initial": 3.0,
        },
        current_dataset={
            "dataset_index": 0,
            "provider_pairs": provider_pairs,
            "manual_point_pairs": manual_pairs,
            "measured_for_fit": measured_rows,
            "pair_count": 7,
        },
        dataset_specs=[
            {
                "dataset_index": 0,
                "theta_initial": 3.0,
                "measured_peaks": list(measured_rows),
                "qr_fit_trial_source_rows_builder": (
                    (lambda local_params=None: dict(trial_source_payload))
                    if not missing_identity
                    else None
                ),
            }
        ],
        geometry_runtime_cfg={"solver": {}, "optimizer": {}, "bounds": {}},
    )
    return {
        "prepared_run": prepared_run,
        "solver_inputs": geometry_fit.GeometryFitRuntimeSolverInputs(
            miller=np.asarray(miller, dtype=float),
            intensities=np.ones(7, dtype=float),
            image_size=64,
        ),
        "saved_var_names": ["theta_initial"],
    }


