def test_build_geometry_manual_fit_dataset_exact_projector_uses_current_local_params(
    monkeypatch,
) -> None:
    bundle_a = _make_stub_caked_bundle(
        detector_shape=(8, 8),
        radial_axis=np.linspace(10.0, 17.0, 8),
        azimuth_axis=np.linspace(-4.0, 3.0, 8),
    )
    bundle_b = _make_stub_caked_bundle(
        detector_shape=(8, 8),
        radial_axis=np.linspace(11.0, 18.0, 8),
        azimuth_axis=np.linspace(-3.0, 4.0, 8),
    )

    resolver_calls: list[dict[str, object]] = []

    def _resolve_bundle(**kwargs):
        resolver_calls.append(dict(kwargs))
        params = dict(kwargs.get("params") or {})
        center = params.get("center", ())
        try:
            center_row = float(center[0])
        except Exception:
            center_row = 0.0
        return bundle_b if center_row > 4.5 else bundle_a

    monkeypatch.setattr(
        geometry_fit,
        "_geometry_fit_resolve_dynamic_reanchor_caked_bundle",
        _resolve_bundle,
    )
    monkeypatch.setattr(
        manual_geometry,
        "_detector_pixel_to_caked_bin",
        lambda live_bundle, col, row: (
            (22.0, -30.0)
            if live_bundle is bundle_a
            else (24.0, -32.0)
            if live_bundle is bundle_b
            else (None, None)
        ),
    )

    callbacks = manual_geometry.make_runtime_geometry_manual_projection_callbacks(
        caked_view_enabled=lambda: True,
        last_caked_background_image_unscaled=lambda: np.zeros((8, 8), dtype=float),
        last_caked_radial_values=lambda: np.linspace(10.0, 17.0, 8),
        last_caked_azimuth_values=lambda: np.linspace(-4.0, 3.0, 8),
        current_background_display=lambda: np.zeros((8, 8), dtype=float),
        current_background_native=lambda: np.ones((8, 8), dtype=float),
        ai=lambda: object(),
        caked_transform_bundle=lambda: bundle_a,
        image_size=lambda: 8,
        display_to_native_sim_coords=lambda col, row, _shape: (float(col), float(row)),
        get_detector_angular_maps=lambda _ai: (_ for _ in ()).throw(
            AssertionError("detector angular maps should not be used")
        ),
        detector_pixel_to_scattering_angles=lambda *_args: (_ for _ in ()).throw(
            AssertionError("analytic forward fallback should not be used")
        ),
    )

    manual_dataset_bindings = geometry_fit.GeometryFitRuntimeManualDatasetBindings(
        osc_files=["C:/tmp/bg0.osc"],
        current_background_index=0,
        image_size=8,
        display_rotate_k=0,
        geometry_manual_pairs_for_index=lambda idx: [
            {
                "q_group_key": ("q", 1),
                "source_table_index": 1,
                "source_row_index": 2,
                "hkl": (1, 1, 0),
                "caked_x": 12.0,
                "caked_y": 14.0,
            }
        ],
        load_background_by_index=lambda idx: (
            np.zeros((8, 8), dtype=np.float64),
            np.zeros((8, 8), dtype=np.float64),
        ),
        apply_background_backend_orientation=lambda image: image,
        geometry_manual_source_rows_for_background=lambda *args, **kwargs: [
            {
                "sim_col_raw": 3.0,
                "sim_row_raw": 4.0,
                "hkl": (1, 1, 0),
                "q_group_key": ("q", 1),
                "source_table_index": 1,
                "source_row_index": 2,
            }
        ],
        geometry_manual_simulated_peaks_for_params=lambda params, *, prefer_cache: [],
        geometry_manual_simulated_lookup=lambda _simulated_peaks: {},
        geometry_manual_entry_display_coords=lambda entry: (
            float(entry.get("caked_x", 0.0)),
            float(entry.get("caked_y", 0.0)),
        ),
        geometry_manual_project_peaks_to_current_view=callbacks.project_peaks_to_current_view,
        geometry_manual_project_peaks_for_background_view=lambda _idx, rows, **_kwargs: (
            callbacks.project_peaks_to_current_view(rows)
        ),
        unrotate_display_peaks=lambda entries, shape, *, k: [dict(entry) for entry in entries],
        display_to_native_sim_coords=lambda col, row, shape: (float(col), float(row)),
        select_fit_orientation=lambda sim_pts, meas_pts, shape, *, cfg: (
            {
                "indexing_mode": "xy",
                "k": 0,
                "flip_x": False,
                "flip_y": False,
                "flip_order": "yx",
                "label": "identity",
            },
            {"pairs": len(sim_pts)},
        ),
        apply_orientation_to_entries=lambda entries, shape, **kwargs: list(entries),
        orient_image_for_fit=lambda image, **kwargs: image,
        pick_uses_caked_space=lambda: True,
        geometry_manual_caked_view_for_index=lambda idx: {
            "background_image": np.zeros((8, 8), dtype=float),
            "radial_axis": np.linspace(10.0, 17.0, 8),
            "azimuth_axis": np.linspace(-4.0, 3.0, 8),
            "transform_bundle": bundle_a,
        },
    )

    dataset = geometry_fit.build_geometry_manual_fit_dataset(
        0,
        theta_base=1.5,
        base_fit_params={"theta_offset": 0.0},
        manual_dataset_bindings=manual_dataset_bindings,
        orientation_cfg={},
    )

    projector = dataset["spec"]["fit_space_projector"]
    result_a = projector(
        np.asarray([3.0], dtype=np.float64),
        np.asarray([4.0], dtype=np.float64),
        local_params={"center": [4.0, 4.0], "gamma": 0.0},
        anchor_kind="simulated",
        input_frame="native_detector",
    )
    result_residual_only = projector(
        np.asarray([3.0], dtype=np.float64),
        np.asarray([4.0], dtype=np.float64),
        local_params={
            "center": [4.0, 4.0],
            "gamma": 1.0,
            "Gamma": 2.0,
            "theta_offset": 1.0,
        },
        anchor_kind="simulated",
        input_frame="native_detector",
    )
    result_b = projector(
        np.asarray([3.0], dtype=np.float64),
        np.asarray([4.0], dtype=np.float64),
        local_params={"center": [5.0, 4.0], "gamma": 1.0},
        anchor_kind="simulated",
        input_frame="native_detector",
    )

    assert result_a["valid"] is True
    assert result_residual_only["valid"] is True
    assert result_b["valid"] is True
    assert result_a["two_theta_deg"].tolist() == [22.0]
    assert result_residual_only["two_theta_deg"].tolist() == [23.0]
    assert result_b["two_theta_deg"].tolist() == [24.0]
    assert len(resolver_calls) == 3
    assert result_a["cake_bundle_signature"] != result_b["cake_bundle_signature"]


@pytest.mark.parametrize(
    ("manual_overrides", "unrotated_native", "expected_detector_call"),
    [
        (
            {"detector_x": 3.0, "detector_y": 4.0},
            (13.0, 24.0),
            (13.0, 24.0),
        ),
        (
            {
                "background_detector_x": 3.0,
                "background_detector_y": 4.0,
                "background_detector_input_frame": "display_detector",
                "fit_detector_x": 13.0,
                "fit_detector_y": 24.0,
            },
            (float("nan"), float("nan")),
            (30.0, 40.0),
        ),
    ],
    ids=["display-detector-alias", "non-native-background-detector-alias"],
)
def test_build_geometry_manual_fit_dataset_reprojects_detector_origin_anchor_for_caked_fit(
    monkeypatch,
    manual_overrides,
    unrotated_native,
    expected_detector_call,
) -> None:
    bundle = _make_stub_caked_bundle(
        detector_shape=(64, 64),
        radial_axis=np.linspace(10.0, 17.0, 8),
        azimuth_axis=np.linspace(-4.0, 3.0, 8),
    )
    detector_calls: list[tuple[float, float]] = []

    monkeypatch.setattr(
        geometry_fit,
        "_geometry_fit_resolve_dynamic_reanchor_caked_bundle",
        lambda **_kwargs: bundle,
    )
    monkeypatch.setattr(
        manual_geometry,
        "_detector_pixel_to_caked_bin",
        lambda live_bundle, col, row: (
            detector_calls.append((float(col), float(row)))
            or (
                (22.5, -35.5)
                if live_bundle is bundle
                and (float(col), float(row)) == tuple(expected_detector_call)
                else (None, None)
            )
        ),
    )

    source_row = {
        "q_group_key": ("q", 1),
        "source_table_index": 1,
        "source_row_index": 2,
        "source_peak_index": 0,
        "source_branch_index": 0,
        "hkl": (1, 1, 0),
        "sim_col": 5.0,
        "sim_row": 6.0,
        "sim_col_raw": 5.0,
        "sim_row_raw": 6.0,
    }
    manual_dataset_bindings = geometry_fit.GeometryFitRuntimeManualDatasetBindings(
        osc_files=["C:/tmp/bg0.osc"],
        current_background_index=0,
        image_size=64,
        display_rotate_k=0,
        geometry_manual_pairs_for_index=lambda idx: [
            {
                "q_group_key": ("q", 1),
                "source_table_index": 1,
                "source_row_index": 2,
                "source_peak_index": 0,
                "source_branch_index": 0,
                "hkl": (1, 1, 0),
                "manual_background_input_origin": "detector",
                "x": 30.0,
                "y": 40.0,
                **dict(manual_overrides),
                "background_two_theta_deg": 999.0,
                "background_phi_deg": -999.0,
                "caked_x": 999.0,
                "caked_y": -999.0,
            }
        ],
        load_background_by_index=lambda idx: (
            np.zeros((64, 64), dtype=np.float64),
            np.zeros((64, 64), dtype=np.float64),
        ),
        apply_background_backend_orientation=lambda image: image,
        geometry_manual_source_rows_for_background=(
            lambda idx, params, *, consumer, required_pairs=None: [dict(source_row)]
        ),
        geometry_manual_simulated_peaks_for_params=(
            lambda params, *, prefer_cache: [dict(source_row)]
        ),
        geometry_manual_simulated_lookup=lambda _simulated_peaks: {(1, 2): dict(source_row)},
        geometry_manual_entry_display_coords=lambda entry: (30.0, 40.0),
        unrotate_display_peaks=lambda entries, shape, *, k: [
            dict(entry, x=float(unrotated_native[0]), y=float(unrotated_native[1]))
            for entry in entries
        ],
        display_to_native_sim_coords=lambda col, row, shape: (float(col), float(row)),
        select_fit_orientation=lambda sim_pts, meas_pts, shape, *, cfg: (
            {
                "indexing_mode": "xy",
                "k": 0,
                "flip_x": False,
                "flip_y": False,
                "flip_order": "yx",
                "label": "identity",
            },
            {"pairs": len(sim_pts)},
        ),
        apply_orientation_to_entries=lambda entries, shape, **kwargs: list(entries),
        orient_image_for_fit=lambda image, **kwargs: image,
        geometry_manual_project_peaks_for_background_view=_identity_geometry_project_rows,
        pick_uses_caked_space=lambda: False,
        geometry_manual_caked_view_for_index=lambda idx: {
            "background_image": np.zeros((8, 8), dtype=float),
            "radial_axis": np.linspace(10.0, 17.0, 8),
            "azimuth_axis": np.linspace(-4.0, 3.0, 8),
            "transform_bundle": bundle,
        },
    )

    dataset = geometry_fit.build_geometry_manual_fit_dataset(
        0,
        theta_base=1.5,
        base_fit_params={"theta_offset": 0.0},
        manual_dataset_bindings=manual_dataset_bindings,
        orientation_cfg={},
    )

    measured = dataset["measured_for_fit"][0]
    initial = dataset["initial_pairs_display"][0]
    display = dataset["measured_display"][0]

    assert measured["background_two_theta_deg"] == pytest.approx(22.5)
    assert measured["background_phi_deg"] == pytest.approx(-35.5)
    assert measured["fit_space_anchor_override"] is True
    assert measured["fit_space_anchor_source"] == "detector_origin_exact_caked_projection"
    assert initial["background_two_theta_deg"] == pytest.approx(22.5)
    assert initial["background_phi_deg"] == pytest.approx(-35.5)
    assert initial["bg_caked_display"] == pytest.approx((22.5, -35.5))
    assert display["background_two_theta_deg"] == pytest.approx(22.5)
    assert display["background_phi_deg"] == pytest.approx(-35.5)
    assert detector_calls == [tuple(expected_detector_call)]


