        calls["cache_data"] = dict(cache_data)
        calls["use_caked_space"] = bool(use_caked_space)
        calls["radial_axis"] = np.asarray(radial_axis, dtype=np.float64)
        calls["azimuth_axis"] = np.asarray(azimuth_axis, dtype=np.float64)
