def test_preflight_probe_selects_00l_branch1_for_saved_branch0() -> None:
    preflight = _load_geometry_preflight_probe_module()
    saved_entry = {
        "hkl": (0, 0, 3),
        "q_group_key": ("q_group", "primary", 0, 3),
        "source_branch_index": 0,
        "source_peak_index": 0,
        "detector_x": 10.0,
        "detector_y": 20.0,
        "sim_col": 10.0,
        "sim_row": 20.0,
    }
    live_entry = {
        "hkl": (0, 0, 3),
        "q_group_key": ("q_group", "primary", 0, 3),
        "source_reflection_index": 71,
        "source_reflection_namespace": "full_reflection",
        "source_reflection_is_full": True,
        "source_row_index": 2,
        "source_branch_index": 1,
        "source_peak_index": 1,
        "sim_col": 10.0,
        "sim_row": 20.0,
    }

    selected = preflight._select_live_candidate_for_saved_entry(
        saved_entry=saved_entry,
        grouped_candidates={("q_group", "primary", 0, 3): [live_entry]},
    )

    assert selected["ok"] is True
    assert selected["selected_candidate"]["source_branch_index"] == 1
    delta, classification = preflight._classify_saved_to_selected_identity_delta(
        saved_entry,
        selected["selected_candidate"],
    )
    assert "source_branch_index" in delta
    assert classification == "legacy_zero_qr_00l_branch_canonicalized"


def test_targeted_source_filter_preserves_q_group_hkl_aliases() -> None:
    required_keys = [
        ((-1, 0, 5), 0, ("q_group", "primary", 1, 5)),
        ((-1, 0, 10), 1, ("q_group", "primary", 1, 10)),
        ((-1, 0, 16), 0, ("q_group", "primary", 1, 16)),
        ((0, 0, 3), None, ("q_group", "primary", 0, 3)),
    ]
    rows = [
        _targeted_source_row(
            hkl=(-1, 0, 5),
            branch_index=0,
            q_group_key=("q_group", "primary", 1, 5),
            sim_col=10.0,
            sim_row=20.0,
        ),
        _targeted_source_row(
            hkl=(1, 0, 10),
            branch_index=1,
            q_group_key=("q_group", "primary", 1, 10),
            sim_col=30.0,
            sim_row=40.0,
            source_peak_index=1,
        ),
        _targeted_source_row(
            hkl=(-1, 1, 16),
            branch_index=0,
            q_group_key=("q_group", "primary", 1, 16),
            sim_col=50.0,
            sim_row=60.0,
            source_peak_index=2,
        ),
        _targeted_source_row(
            hkl=(0, 0, 3),
            branch_index=1,
            q_group_key=("q_group", "primary", 0, 3),
            sim_col=70.0,
            sim_row=80.0,
            source_peak_index=3,
        ),
        _targeted_source_row(
            hkl=(9, 9, 9),
            branch_index=0,
            q_group_key=("q_group", "primary", 9, 9),
            sim_col=90.0,
            sim_row=100.0,
            source_peak_index=4,
        ),
    ]

    filtered_rows, counts, matched_keys = (
        geometry_fit._geometry_fit_filter_entries_for_required_branch_groups(
            rows,
            required_keys,
        )
    )

    assert [(row["q_group_key"], row.get("source_branch_index")) for row in filtered_rows] == [
        (("q_group", "primary", 1, 5), 0),
        (("q_group", "primary", 1, 10), 1),
        (("q_group", "primary", 1, 16), 0),
        (("q_group", "primary", 0, 3), 1),
    ]
    assert counts["after_branch_filter_count"] == 4
    assert counts["unrelated_count"] == 1
    assert matched_keys == required_keys


def test_new4_live_source_coverage_materializes_collapsed_003_alias() -> None:
    key = ("q_group", "primary", 0, 3)
    required_pair = _targeted_required_pair(
        pair_id="bg0:pair0",
        hkl=(0, 0, 3),
        branch_index=0,
        q_group_key=key,
        extra={
            "source_reflection_index": 10,
            "source_reflection_namespace": "full_reflection",
            "source_reflection_is_full": True,
            "source_row_index": 24,
            "source_peak_index": 0,
        },
    )
    collapsed_row = _targeted_source_row(
        hkl=(0, 0, 3),
        branch_index=1,
        q_group_key=key,
        sim_col=70.0,
        sim_row=80.0,
        source_peak_index=1,
    )
    collapsed_row.update(
        {
            "source_reflection_index": 71,
            "source_reflection_namespace": "full_reflection",
            "source_reflection_is_full": True,
            "source_coverage_aliases": [
                {
                    "hkl": (0, 0, 3),
                    "branch_slot": "00l_collapsed",
                    "branch_index": None,
                    "q_group_key": key,
                    "source_reflection_index": 10,
                    "source_reflection_namespace": "full_reflection",
                    "source_reflection_is_full": True,
                    "source_row_index": 24,
                    "source_peak_index": 0,
                }
            ],
            "is_00l_collapsed": True,
        }
    )

    filtered_rows, counts, matched_keys = (
        geometry_fit._geometry_fit_filter_entries_for_required_branch_groups(
            [collapsed_row],
            [geometry_fit._geometry_fit_required_branch_group_key(required_pair)],
        )
    )
    validation = geometry_fit.validate_geometry_fit_live_source_rows(
        filtered_rows,
        required_pairs=[required_pair],
    )

    assert len(filtered_rows) == 1
    assert filtered_rows[0]["is_00l_collapsed"] is True
    assert counts["after_branch_filter_count"] == 1
    assert matched_keys == [((0, 0, 3), None, key)]
    assert validation["valid"] is True
    assert validation["resolved_pairs"][0]["resolution_kind"] in {
        "source_coverage_alias",
        "zero_qr_00l_branch_unconstrained",
    }
    assert collapsed_row["source_coverage_aliases"]


