def _assert_targeted_preflight_filters_required_groups_only() -> None:
    required_pairs = [
        _targeted_required_pair(
            pair_id="bg0:pair0",
            hkl=(1, 0, 0),
            branch_index=1,
            q_group_key=("q", 1),
        ),
        _targeted_required_pair(
            pair_id="bg0:pair1",
            hkl=(2, 0, 0),
            branch_index=0,
            q_group_key=("q", 2),
        ),
    ]
    targets = geometry_fit.collect_geometry_fit_required_manual_fit_targets(
        required_pairs,
        background_index=0,
    )
    required_keys = geometry_fit._geometry_fit_required_branch_group_keys(targets)
    filtered_rows, counts, matched_keys = (
        geometry_fit._geometry_fit_filter_entries_for_required_branch_groups(
            [
                _targeted_source_row(
                    hkl=(1, 0, 0),
                    branch_index=1,
                    q_group_key=("q", 1),
                    sim_col=10.0,
                    sim_row=20.0,
                ),
                _targeted_source_row(
                    hkl=(1, 0, 0),
                    branch_index=0,
                    q_group_key=("q", 1),
                    sim_col=11.0,
                    sim_row=21.0,
                    source_peak_index=1,
                ),
                _targeted_source_row(
                    hkl=(2, 0, 0),
                    branch_index=0,
                    q_group_key=("q", 2),
                    sim_col=30.0,
                    sim_row=40.0,
                    source_peak_index=2,
                ),
                _targeted_source_row(
                    hkl=(9, 9, 9),
                    branch_index=0,
                    q_group_key=("q", 9),
                    sim_col=50.0,
                    sim_row=60.0,
                    source_peak_index=3,
                ),
            ],
            required_keys,
        )
    )

    assert counts == {
        "total_count": 4,
        "after_hkl_filter_count": 3,
        "after_branch_filter_count": 2,
        "unrelated_count": 2,
    }
    assert [(row["hkl"], row.get("source_branch_index")) for row in filtered_rows] == [
        ((1, 0, 0), 1),
        ((2, 0, 0), 0),
    ]
    assert matched_keys == [
        ((1, 0, 0), 1, ("q", 1)),
        ((2, 0, 0), 0, ("q", 2)),
    ]


