    assert lines[1] == "bg0.osc: all saved manual pairs strictly resolved."
    assert any(
        "saved_branch=0(caked_y)" in line
        and "fit_branch=0(source_branch_index)" in line
        and "fallback_branch=0(source_branch_index)" in line
        for line in lines[2:]
    )


