def test_new4_coordinate_audit_cli_accepts_objective_step_flags(
    monkeypatch,
    tmp_path,
) -> None:
    module = _load_new4_coordinate_audit_module()
    captured = {}

    def fake_run_coordinate_audit(**kwargs):
        captured.update(kwargs)
        return {
            "status": "pass",
            "json_path": str(tmp_path / "audit.json"),
            "png_path": str(tmp_path / "audit.png"),
        }

    monkeypatch.setattr(module, "run_coordinate_audit", fake_run_coordinate_audit)

    rc = module.main(
        [
            "--state",
            str(tmp_path / "new4.json"),
            "--output-root",
            str(tmp_path),
            "--objective-audit",
            "--after-objective-step",
            "--step-param",
            "center_x",
            "--step-size",
            "0.25",
        ]
    )

    assert rc == 0
    assert captured["objective_audit"] is True
    assert captured["after_objective_step"] is True
    assert captured["step_param"] == "center_x"
    assert captured["step_size"] == pytest.approx(0.25)
    assert captured["report_label"] == "Bi2Se3"


def test_caked_point_reprojection_recomputes_when_theta_changes(tmp_path) -> None:
    report, projector_calls, _module = _run_stub_caked_point_reprojection(tmp_path)
    report_path = tmp_path / "new4_run" / _module.REPORT_NAME
    file_report = json.loads(report_path.read_text(encoding="utf-8"))

    assert report["status"] == "pass"
    assert file_report["status"] == report["status"]
    assert file_report["point_only_reprojection_called"] is True
    assert report["point_only_reprojection_called"] is True
    assert len(projector_calls) == 3
    assert all(call["input_frame"] == "native_detector" for call in projector_calls)
    assert report["theta_projector_signature_changed"] is True
    assert report["theta_point_shift_required"] is False
    assert report["all_theta_reprojected_points_finite"] is True
    assert report["exact_projector_available"] is True
    assert report["all_exact_projector_used"] is True
    assert report["all_projection_projector_kinds_exact"] is True
